import{analytics as n}from"./analytics.CPFqoLBP.js";document.addEventListener("click",r=>{const t=r.target.closest("[data-analytics-id], [data-calendly-trigger], [data-modal-trigger]");if(t){const a=t.getAttribute("data-analytics-id")||t.id||"anonymous_cta",e=t.getAttribute("data-analytics-location")||"unknown",i=t.innerText||"no_text";t.hasAttribute("data-calendly-trigger")?n.trackCTA(a,e,i):t.hasAttribute("data-modal-trigger")||n.trackCTA(a,e,i)}},{passive:!0});
